mapper.insert:
/* FileMapper.insertFile */
INSERT INTO TB_FILE_INFO (
	 ATCHFILENO
	,FILEORD
	,ORGFILENM
	,SVFILENM
	,FILEEXT
	,FILEDIR
	,FILESIZE
	,REG_ID
	,REG_DT
	,DWLD_CNT
) VALUES (
	 #{atchfileno}
	,#{fileord}
	,#{orgfilenm}
	,#{svfilenm}
	,#{fileext}
	,#{filedir}
	,#{filesize}
	,#{userId}
	,now()
	,0
)

mapper.delete:
/* FileMapper.deleteFile */
DELETE FROM
	TB_FILE_INFO
WHERE
	ATCHFILENO = #{atchfileno}
AND
	FILEORD	= #{fileord}

mapper.update:
/* FileMapper.updateFileCount */
UPDATE
	TB_FILE_INFO
SET
	DWLD_CNT = DWLD_CNT + 1
WHERE
	ATCHFILENO = #{atchfileno}
AND
	FILEORD	= #{fileord}
